import { useRef, useMemo, useState } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import * as THREE from 'three';

function LargeParticles() {
  const pointsRef = useRef<THREE.Points>(null!);

  const count = 20;
  const radius = 2;
  const { positions, colors, thetas, phis, floatPhases } = useMemo(() => {
    const positions = new Float32Array(count * 3);
    const colors = new Float32Array(count * 3);
    const thetas = new Float32Array(count);
    const phis = new Float32Array(count);
    const floatPhases = new Float32Array(count);

    const colorList = [
      new THREE.Color('#cc5500'),
      new THREE.Color('#8489F7'),
      new THREE.Color('#73AEF8'),
      new THREE.Color('#61D3F8'),
      new THREE.Color('#a259ff'),
    ];

    for (let i = 0; i < count; i++) {
      const theta = Math.acos(2 * Math.random() - 1);
      const phi = 2 * Math.PI * Math.random();
      thetas[i] = theta;
      phis[i] = phi;
      floatPhases[i] = Math.random() * Math.PI * 2;

      const x = radius * Math.sin(theta) * Math.cos(phi);
      const y = radius * Math.sin(theta) * Math.sin(phi);
      const z = radius * Math.cos(theta);

      positions.set([x, y, z], i * 3);

      const c = colorList[Math.floor(Math.random() * colorList.length)];
      colors.set([c.r, c.g, c.b], i * 3);
    }

    return { positions, colors, thetas, phis, floatPhases };
  }, []);

  useFrame((state) => {
    if (!pointsRef.current) return;
    const time = state.clock.getElapsedTime();
    const posAttr = pointsRef.current.geometry.attributes.position;

    for (let i = 0; i < count; i++) {
      const theta = thetas[i] + 0.15 * Math.sin(time * 0.7 + i);
      const phi = phis[i] + 0.15 * Math.cos(time * 0.9 + i * 1.7);
      const floatR = 0.12 * Math.sin(time * 1.1 + floatPhases[i]);
      const r = radius + floatR;

      const x = r * Math.sin(theta) * Math.cos(phi);
      const y = r * Math.sin(theta) * Math.sin(phi);
      const z = r * Math.cos(theta);

      posAttr.setXYZ(i, x, y, z);
    }
    posAttr.needsUpdate = true;
  });

  const circleTexture = useMemo(() => {
    const canvas = document.createElement('canvas');
    canvas.width = canvas.height = 32;
    const ctx = canvas.getContext('2d')!;
    ctx.clearRect(0, 0, 32, 32);
    ctx.beginPath();
    ctx.arc(16, 16, 16, 0, Math.PI * 2);
    ctx.closePath();
    ctx.fillStyle = '#ffffff';
    ctx.fill();
    return new THREE.CanvasTexture(canvas);
  }, []);

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" count={count} array={positions} itemSize={3} />
        <bufferAttribute attach="attributes-color" count={count} array={colors} itemSize={3} />
      </bufferGeometry>
      <pointsMaterial
        size={0.15}
        vertexColors
        map={circleTexture}
        transparent
        depthWrite={false}
        alphaTest={0.01}
        sizeAttenuation
      />
    </points>
  );
}

function SmallParticles() {
  const pointsRef = useRef<THREE.Points>(null!);

  const count = 200;
  const radius = 2.25;
  const maxLife = 200;

  const { positions, colors, thetas, phis, floatPhases, lifetimes } = useMemo(() => {
    const positions = new Float32Array(count * 3);
    const colors = new Float32Array(count * 3);
    const thetas = new Float32Array(count);
    const phis = new Float32Array(count);
    const floatPhases = new Float32Array(count);
    const lifetimes = new Uint16Array(count);

    for (let i = 0; i < count; i++) {
      thetas[i] = Math.acos(2 * Math.random() - 1);
      phis[i] = 2 * Math.PI * Math.random();
      floatPhases[i] = Math.random() * Math.PI * 2;
      lifetimes[i] = Math.floor(Math.random() * maxLife);
      colors.set([1, 1, 1], i * 3);
    }

    return { positions, colors, thetas, phis, floatPhases, lifetimes };
  }, []);

  useFrame((state) => {
    if (!pointsRef.current) return;
    const time = state.clock.getElapsedTime();
    const posAttr = pointsRef.current.geometry.attributes.position;
    const colAttr = pointsRef.current.geometry.attributes.color;

    for (let i = 0; i < count; i++) {
      lifetimes[i]++;
      if (lifetimes[i] > maxLife) {
        thetas[i] = Math.acos(2 * Math.random() - 1);
        phis[i] = 2 * Math.PI * Math.random();
        floatPhases[i] = Math.random() * Math.PI * 2;
        lifetimes[i] = 0;
      }

      let alpha = 1;
      if (lifetimes[i] < maxLife * 0.1) {
        alpha = lifetimes[i] / (maxLife * 0.1);
      } else if (lifetimes[i] > maxLife * 0.9) {
        alpha = 1 - (lifetimes[i] - maxLife * 0.9) / (maxLife * 0.1);
      }

      colAttr.setXYZ(i, alpha, alpha, alpha);

      const theta = thetas[i] + 0.08 * Math.sin(time * 0.8 + i);
      const phi = phis[i] + 0.08 * Math.cos(time * 1.1 + i * 1.3);
      const floatR = 0.08 * Math.sin(time * 1.2 + floatPhases[i]);
      const r = radius + floatR;

      const x = r * Math.sin(theta) * Math.cos(phi);
      const y = r * Math.sin(theta) * Math.sin(phi);
      const z = r * Math.cos(theta);

      posAttr.setXYZ(i, x, y, z);
    }
    posAttr.needsUpdate = true;
    colAttr.needsUpdate = true;
  });

  const circleTexture = useMemo(() => {
    const canvas = document.createElement('canvas');
    canvas.width = canvas.height = 32;
    const ctx = canvas.getContext('2d')!;
    ctx.clearRect(0, 0, 32, 32);
    ctx.beginPath();
    ctx.arc(16, 16, 16, 0, Math.PI * 2);
    ctx.closePath();
    ctx.fillStyle = '#a1a1aa'; // a bit darker for small ones, like in vue (greyish)
    ctx.fill();
    return new THREE.CanvasTexture(canvas);
  }, []);

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" count={count} array={positions} itemSize={3} />
        <bufferAttribute attach="attributes-color" count={count} array={colors} itemSize={3} />
      </bufferGeometry>
      <pointsMaterial
        size={0.035}
        vertexColors
        map={circleTexture}
        transparent
        depthWrite={false}
        opacity={0.85}
        alphaTest={0.01}
        sizeAttenuation
      />
    </points>
  );
}

function MainScene() {
  const sphereRef = useRef<THREE.Mesh>(null!);

  useFrame(() => {
    if (sphereRef.current) {
      sphereRef.current.rotation.y += 0.002;
    }
  });

  return (
    <group>
      <mesh ref={sphereRef}>
        <sphereGeometry args={[2, 30, 30]} />
        <meshBasicMaterial color="#333337" wireframe={true} transparent opacity={0.6} />
      </mesh>
      <LargeParticles />
      <SmallParticles />
    </group>
  );
}

export default function VortexBackground() {
  const [hovered, setHovered] = useState(false);

  return (
    <div 
      className="absolute inset-0 z-0 bg-[#040409]"
      onPointerOver={() => setHovered(true)}
      onPointerOut={() => setHovered(false)}
    >
      <Canvas camera={{ position: [0, 3, 5], fov: 40 }} dpr={[1, 2]}>
        <MainScene />
        <OrbitControls enableZoom={false} enablePan={false} autoRotate={!hovered} autoRotateSpeed={0.5} maxPolarAngle={Math.PI / 1.5} minPolarAngle={Math.PI / 3} />
      </Canvas>
      {/* Overlays to blend with the rest of the page */}
      <div className="absolute inset-0 bg-gradient-to-t from-zinc-950 via-transparent to-zinc-950/80 pointer-events-none" />
      <div className="absolute inset-0 bg-gradient-to-b from-zinc-950 via-transparent to-transparent opacity-50 pointer-events-none" />
    </div>
  );
}

